dashboard.definition:
{
  "title": "Source - MSSQL",
  "description": "Microsoft SQL Server error logs — database health, error detection, and backup monitoring",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total Events Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:mssql:errorlog\" by _time span=1h"
      }
    },
    "ds_errors": {
      "type": "ds.search",
      "name": "Error Count",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:mssql:errorlog\" \"Error:\" | stats count"
      }
    },
    "ds_warnings": {
      "type": "ds.search",
      "name": "Warning Count",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:mssql:errorlog\" (\"Severity: 10\" OR \"Severity: 11\" OR \"Severity: 12\" OR \"Severity: 13\") | stats count"
      }
    },
    "ds_backup_events": {
      "type": "ds.search",
      "name": "Backup Events",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:mssql:errorlog\" \"BACKUP DATABASE\" | stats count"
      }
    },
    "ds_events_by_severity": {
      "type": "ds.search",
      "name": "Events Over Time by Severity",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:mssql:errorlog\" | eval sev_cat=case(match(_raw,\"Severity: (1[6-9]|2[0-5])\"),\"Critical (16+)\",match(_raw,\"Severity: (1[0-5])\"),\"Warning (10-15)\",match(_raw,\"Error:\"),\"Error\",match(_raw,\"Backup\"),\"Backup\",1=1,\"Info\") | timechart span=1h count by sev_cat"
      }
    },
    "ds_event_categories": {
      "type": "ds.search",
      "name": "Events by Category",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:mssql:errorlog\" | eval category=case(match(_raw,\"Login\"),\"Login\",match(_raw,\"BACKUP\"),\"Backup\",match(_raw,\"Severity: (1[6-9]|2[0-5])\"),\"Critical Error\",match(_raw,\"Error:\"),\"Error\",match(_raw,\"Warning\"),\"Warning\",1=1,\"Info\") | stats count by category | sort -count"
      }
    },
    "ds_top_errors": {
      "type": "ds.search",
      "name": "Top Error Messages",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:mssql:errorlog\" \"Error:\" | rex \"Error: (?<error_num>\\d+)\" | stats count by error_num | sort -count | head 15 | rename error_num as \"Error Number\""
      }
    },
    "ds_recent_errors": {
      "type": "ds.search",
      "name": "Recent Errors and Warnings",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:mssql:errorlog\" (\"Error:\" OR \"Warning\") | table _time host message | sort -_time | head 30 | rename message as \"Message\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — MSSQL\n\n**Sourcetype:** `FAKE:mssql:errorlog` | **Coverage:** SQL-PROD-01 (Boston) | **Format:** SQL Server Error Log\n\n**Why monitor?** Prevent database outages — detect errors early, track backup success, monitor query performance.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_events": {
      "type": "splunk.singlevalue",
      "title": "Total Events",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_errors": {
      "type": "splunk.singlevalue",
      "title": "Errors",
      "dataSources": { "primary": "ds_errors" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_warnings": {
      "type": "splunk.singlevalue",
      "title": "Warnings",
      "dataSources": { "primary": "ds_warnings" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#F8BE34",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_backups": {
      "type": "splunk.singlevalue",
      "title": "Backup Events",
      "dataSources": { "primary": "ds_backup_events" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#53A051",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_events_by_severity": {
      "type": "splunk.area",
      "title": "Events Over Time by Severity",
      "dataSources": { "primary": "ds_events_by_severity" },
      "options": {
        "stackMode": "stacked",
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "areaOpacity": 0.7,
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Events / hour",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColorsByField": {
          "Info": "#00D2FF",
          "Backup": "#53A051",
          "Warning (10-15)": "#F8BE34",
          "Error": "#F1813F",
          "Critical (16+)": "#DC4E41"
        }
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_event_categories": {
      "type": "splunk.pie",
      "title": "Events by Category",
      "dataSources": { "primary": "ds_event_categories" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColorsByField": {
          "Login": "#53A051",
          "Backup": "#7B56DB",
          "Info": "#00D2FF",
          "Error": "#F1813F",
          "Critical Error": "#DC4E41",
          "Warning": "#F8BE34"
        }
      }
    },
    "viz_top_errors": {
      "type": "splunk.bar",
      "title": "Top Error Messages",
      "dataSources": { "primary": "ds_top_errors" },
      "options": {
        "seriesColors": ["#DC4E41"],
        "legendDisplay": "off",
        "xAxisTitleText": "Occurrences",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_errors_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent Errors and Warnings",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_recent_errors": {
      "type": "splunk.table",
      "title": "Recent Errors and Warnings",
      "dataSources": { "primary": "ds_recent_errors" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 130 } },
      { "item": "viz_kpi_total_events", "type": "block", "position": { "x": 0, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_kpi_errors", "type": "block", "position": { "x": 300, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_kpi_warnings", "type": "block", "position": { "x": 600, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_kpi_backups", "type": "block", "position": { "x": 900, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_events_by_severity", "type": "block", "position": { "x": 0, "y": 250, "w": 750, "h": 350 } },
      { "item": "viz_event_categories", "type": "block", "position": { "x": 750, "y": 250, "w": 450, "h": 350 } },
      { "item": "viz_top_errors", "type": "block", "position": { "x": 0, "y": 600, "w": 1200, "h": 300 } },
      { "item": "viz_errors_header", "type": "block", "position": { "x": 0, "y": 900, "w": 1200, "h": 50 } },
      { "item": "viz_recent_errors", "type": "block", "position": { "x": 0, "y": 950, "w": 1200, "h": 400 } }
    ]
  }
}
